INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (36, 1, 36, '【読解】「私は１０年前に日本へ留学しました。最初はほとんど日本語が話せませんでしたが、毎日ニュースを見たり、日本人の友達と話したりして、少しずつ上手になりました。」筆者はどうやって日本語が上手になりましたか。', 'single_choice', 1);
INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (37, 1, 37, 'A: あの、新しいプロジェクトの資料、もう読みましたか。 B: いいえ、＿＿。今日の午後読むつもりです。', 'single_choice', 1);
