INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (79, 2, 39, '【読解】「この会社では、１日に３回ミーティングがあります。１回目は９時、２回目は１３時、３回目は１７時に行われます。」ミーティングは１日に何回行われますか。', 'single_choice', 1);
INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (80, 2, 40, '【読解】「最近、日本語の勉強があまり進んでいません。仕事が忙しくて、家に帰るといつも疲れてしまいます。それでも、日本語が上手になりたいので、毎日３０分だけでも勉強を続けようと思っています。」筆者はこれからどうしようと思っていますか。', 'single_choice', 1);
